diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..51bc66e958b2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -485,6 +485,19 @@ static Value *foldLogOpOfMaskedICmps_NotAllZeros_BMask_Mixed(
       ICmp->setSameSign(false);
     return RHS;
   }
+
+  // If B has exactly one extra bit than D, that bit is guaranteed to be set
+  // because LHS is true and all bits in D are known to be zero from RHS, so LHS
+  // is also subsumed by RHS.
+  // (icmp ne (A & 3), 0) & (icmp eq (A & 2), 2) -> (icmp eq (A & 2), 2)
+  APInt ExtraBits = *BCst & ~*DCst;
+  if (ExtraBits.isPowerOf2()) {
+    // We can't guarantee that samesign hold after this fold.
+    if (auto *ICmp = dyn_cast<ICmpInst>(RHS))
+      ICmp->setSameSign(false);
+    return RHS;
+  }
+
   // Otherwise, LHS and RHS contradict and the whole expression becomes false
   // (or true if negated.) For example,
   // (icmp ne (A & 7), 0) & (icmp eq (A & 15), 8) -> false.

